    ['Lebros Supplies'] = {
        id = 22,
        start_npc = nil,
        start_zone = 'Lebros Cavern',
        start_pos = nil,
        description = 'Deliver the provisions',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'Feed all 12 of the soldiers.\n1. Yazuhma will keep you supplied with tasty treats for those hard working soldiers. She will only give one supply out every few seconds, so at the beginning you will have to wait as she hands things to you one by one.\n2. Yazuhma will report to you how many soldiers are still hungry with the following messages:\n      - 7-12 remaining: "There are still brave soldiers starving out there."\n      - 4-6 remaining: "It looks like about half of the advance unit has recieved their rations."\n      - 2-3 remaining: "Not many hungry soldiers left, I\'d wager!"\n      - 1 remaining: "There must be somebody out there still waiting for you."\n3. Yazuhma will give you one of five foods. It is generally accepted that these foods have different values.\n      -  Seafood Stewpot: 7 Points + AoE effect that covers the entire group the soldier is part of.\n      -  Bison Steak: 5 Points.\n      -  Coeurl Sub: 4 Points.\n      -  Bison Jerky: 3 Points.\n      -  Pea Soup: 2 Points.\n      -  White Bread: 1 Point.\n4. Each soldier needs 7 points to be full.\n   - This may have been nerfed, Bison Steak+White Bread= 6 points, but filled the last soldier and unlocked the rune of release. Javelinx (talk) 08:08, 1 September 2025 (UTC)\n5. Talking to a Imperial Stormer soldier NPC with food in your possession will automatically feed it to them.\n6. You can tell if a soldier is full or not by talking to him with no food in your inventory.\n      - A hungry soldier will ask you "Have you brought the provisions?"\n      - A satiated soldier will say "There\'s nothing like a full belly...".\n7. When you feed a soldier they will give you a different message based on whether they were full already or not:\n      - If the soldier was hungry before you fed it you will recieve the message "Thank Zahak you\'re here. I was about to start eating my boots."\n      - If the soldier was full before you fed it you will recieve the message "You brought more supplies? Well, you can never have too much..."\n8. The soldiers within a particular area all have different types of shields, which are useful for telling them apart. The shields are as follows:\n      -  Spiked Buckler\n      -  Balance Buckler\n      -  Gold Buckler\n9. There are 2 soldiers in the west-south-west, 2 in south-south-west, 3 in the south-east, 3 in the north-west and 2 at the North.\n10. The Rune of Release spawns at Yazuhma.',
        notes = '1. This assault appears to have been ninja-nerfed, as it now takes fewer points to fully feed an NPC.\n2. Crimson Erucas aggro  true sound from a distance of around 8\', and will detect through Sneak(Status).\n3. Crimson Erucas are susceptible to Bind, Weight and Sleep.\n4. Due to the many circular obstacles scattered around the maps (i.e. lava pools), it is fairly easy to continue delivering provisions with several crawlers on you if you have some form of movement speed+.\n5. Crimson Erucas seem to never deaggro.\n6. When passive, Crimson Erucas move back to their home areas at an extremely slow pace.',
    },
    ['Leujaoam Cleansing'] = {
        id = 1,
        start_npc = nil,
        start_zone = 'Leujaoam Sanctum',
