    ['Lost and Found'] = {
        id = 47,
        start_npc = nil,
        start_zone = 'Ilrusi Atoll',
        start_pos = nil,
        description = 'Find the ring',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'To win this assault, find the lost ring.\n1. The best way of doing this is to find the first clue with party members spread out on the map as you try to triangulate the rings position.\nSpeak with Tian Tian to get her to follow you.\n2. Walk around and then speak again with Tian Tian.\n   - Who, after taking her sweet time will provide you statements about the location of nearby clues.\n3. Initially, Tian Tian will only inform you about the proximity of the nearest clue.\n4. When you are close to a clue (~1\'), a ??? will spawn.\n5. Click on the ??? quickly to check the clue.  There are 4 possible outcomes:\n   - A Kelp Crab will spawn.\n   - You will find Seaweed, which will cause a Gravity effect.\n   - You will find a hint, which will upgrade Tian Tian\'s mystic powers of divination.\n   - Nothing happens.\n6. Upon finding the first hint, Tian Tian will begin informing the party about to the ring.\n7. At this point, the party can use triangulation to zero in on the ring.\n8. Further clues will enhance the messages from Tian Tian:\n   - 0 clues - Tian Tian will say there is either something to be found or nothing to be found near. No hints about the ring position.\n   - 1 clue  - Tian Tian begins saying which party member is closest to the ring.\n   - 2 clues - Tian Tian begins giving the ring\'s approximate direction from her current position, regardless of physical obstacles (like impassable walls or water) that may separate the player from the ring.\n   - 3 clues - Tian Tian beings giving distance numbers in yalms from the ring. Again, she won\'t take into consideration anything between you and the ring.\n9. If you are very close to the ring, the ??? will spawn.  Click on it quickly to retrieve the Eye of Zahak.\n10. The first two statements given by Tian Tian only refer to any nearby hints, not the location of the ring (unless you have already found the 3 hints).  Only use the additional hint info (closest player, approximate location, and distance) to find the ring.\nThe Rune of Release will spawn at the start point when the ring is retrieved.',
        notes = '1. Kelp Crabs are a possible spawn when a ??? is triggered.',
    },
    ['Marids in the Mist'] = {
        id = 18,
        start_npc = nil,
        start_zone = 'Mamool Ja Training Grounds',
        start_pos = nil,
        description = 'Neutralize the Marids',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'You complete this Assault by killing or subduing all 8 Marids. You will get more Assault Points for subduing the 8 Marids without killing them.  In order to subdue a Marid, use the Temporary Item Thunderguard Dart on the marid.  If successful, the marid will despawn and you will be credited with capturing it.\n1. Thunderguard Darts can be obtained by talking to the starting NPC, Zimahd.  Despite how rare and expensive he claims them to be, he has an infinite supply of darts.\n2. Each person can only carry one dart at a time.\n3. The best time to use a dart on a Marid is when the Marid has 0 TP (right after a weaponskill) and low HP (below 50%). When timed properly, successful capture is virtually guaranteed.\nTo unlock the Rune of Release at the southwest of (I-9), capture or kill all 8 marids.\n4. 1333 base points will be awarded for capturing all 8 marids.\n   - 2198 points awarded for capturing all 8 marids solo (with assault band bonus, of course)\n5. 266 base points will be awarded for killing all 8 marids.',
        notes = '1. Marids spawn a single Chigoe when they use a TP move.\n2. Mamool Ja can be avoided with Invisible (Status).',
    },
