        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'Kill 35 Chigoes to complete this assault.  The Rune of Release spawns at H-8.\n1. Be sure to thoroughly check in and around the cages in the dead-end rooms for hidden Chigoe.\n2. Using //fillmode greatly improve ability to spot the Chigoes.',
