        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = 'Defeat King Goldemar.',
        notes = '1. King Goldemar is a Black Mage, and as such he can cast tier 3-ga spells. He can also cast ancient magic, and sleepga.\n2. King Goldemar has an EXTREMELY fast casting rate.\n3. King Goldemar is very resistant to all enfeebles, including Dispel. (But not Finale)\n4. Throughout the fight King Goldemar will call in the animated weapons one by one. He will announce in say when he is calling a weapon, and will say exactly which weapon is coming.\n5. King Goldemar will use regular dvergr weaponskills.',
    },
    ['The Susanoo Shuffle'] = {
        id = 20,
        start_npc = nil,
        start_zone = 'Mamool Ja Training Grounds',
